var createUserIntoDB = async (payload) => {
  const { name, email, password, role } = payload;
  const isExist = await prisma.user.findUnique({
    where: {
      email
    }
  });
  if (isExist) {
    throw new Error("User already Exist");
  }
  const hashPassword = await bcrypt.hash(
    password,
    Number(config_default.bcrypt_hash_pass)
  );
  const createUser2 = await prisma.user.create({
    data: {
      name,
      email,
      password: hashPassword,
      role
    },
    omit: {
      password: true
    }
  });
  const user = await prisma.user.findUnique({
    where: {
      id: createUser2.id,
      email: createUser2.email
    },
    omit: {
      password: true
    }
  });
  return user;
};
var loginUser = async (payload) => {
  const { email, password } = payload;
  const matchUser = await prisma.user.findUniqueOrThrow({
    where: {
      email
    }
  });
  if (matchUser.status === "BLOCKED") {
    throw new Error("User account Blocked");
  }
  const matchPassword = await bcrypt.compare(password, matchUser.password);
  if (!matchPassword) {
    throw new Error("Password incorrect");
  }
  const jwtPayload = {
    id: matchUser.id,
    name: matchUser.name,
    email: matchUser.email,
    role: matchUser.role
  };
  const accessToken = jwtUtils.createToken(
    jwtPayload,
    config_default.access_token_secret_key,
    { expiresIn: config_default.access_token_expire_in }
  );
  const refreshToken3 = jwtUtils.createToken(
    jwtPayload,
    config_default.refresh_token_secret_key,
    { expiresIn: config_default.refresh_token_expire_in }
  );
  return {
    accessToken,
    refreshToken: refreshToken3
  };
};
