// src/middleware/auth.ts
import httpStatus2 from "http-status";
var auth = (...requiredRole) => {
  return catchAsync(async (req, res, next) => {
    const token = req.cookies.accessToken ? req.cookies.accessToken : req.headers.authorization?.startsWith("Bearer") ? req.headers.authorization?.split(" ")[1] : req.headers.authorization;
    if (!token) {
      throw new Error("You are not log in");
    }
    const verified = jwtUtils.verifyToken(token, config_default.access_token_secret_key);
    if (!verified.success) {
      throw new Error(verified.error);
    }
    const { email, name, id, role } = verified.data;
    if (requiredRole.length && !requiredRole.includes(role)) {
      return res.status(403).json({
        success: false,
        statusCode: httpStatus2.FORBIDDEN,
        message: "Forbidden,you don't have permission this route ! Because you r not owner"
      });
    }
    const user = await prisma.user.findUnique({
      where: {
        id,
        email,
        name,
        role
      }
    });
    if (!user) {
      throw new Error("Please Login in");
    }
    if (user.status === "BLOCKED") {
      throw new Error("YOU account has been blocked");
    }
    req.user = {
      id,
      name,
      role,
      email
    };
    next();
  });
};

