// src/modular/gear/gear.service.ts
var getAllGear = async (query) => {
  const minPrice = query.minPrice ? Number(query.minPrice) : void 0;
  const maxPrice = query.maxPrice ? Number(query.maxPrice) : void 0;
  const andCondition = [];
  if (query.brand) {
    andCondition.push({
      brand: {
        contains: query.brand,
        mode: "insensitive"
      }
    });
  }
  if (query.category) {
    andCondition.push({
      category: {
        name: {
          contains: query.category,
          mode: "insensitive"
        }
      }
    });
  }
  if (query.minPrice) {
    andCondition.push({
      pricePerDay: {
        gte: minPrice,
        lte: maxPrice
      }
    });
  }
  if (query.maxPrice) {
    andCondition.push({
      pricePerDay: {
        lte: maxPrice
      }
    });
  }
  const gear = await prisma.gear.findMany({
    where: {
      AND: andCondition
    },
    include: {
      category: true,
      provider: {
        select: {
          id: true,
          name: true,
          email: true,
          role: true
        }
      }
    },
    orderBy: {
      createdAt: "desc"
    }
  });
  return gear;
};
var getGearById = async (id) => {
  const gear = await prisma.gear.findUnique({
    where: {
      id
    },
    include: {
      category: true,
      provider: {
        select: {
          id: true,
          name: true,
          email: true,
          role: true
        }
      }
    }
  });
  return gear;
};
