import { Router as Router8 } from "express";

// src/modular/payment/payment.controller.ts
import httpStatus10 from "http-status";

// src/modular/payment/payment.service.ts
import Stripe from "stripe";
var stripe = new Stripe(process.env.STRIPE_SECRET_KEY);
var createPayment = async (userId, payload) => {
  const { rentalId } = payload;
  const result = await prisma.$transaction(async (tx) => {
    const rental = await tx.rental.findUniqueOrThrow({
      where: {
        id: rentalId
      },
      include: {
        gear: true
      }
    });
    if (rental.customerId !== userId) {
      throw new Error("You can pay only for your own rental");
    }
    const existingPayment = await tx.payment.findUnique({
      where: {
        rentalId
      }
    });
    if (existingPayment) {
      throw new Error("Payment already exists for this rental");
    }
    const session = await stripe.checkout.sessions.create({
      line_items: [
        {
          price_data: {
            currency: "usd",
            product_data: {
              name: "Gear Rental"
            },
            // unit_amount: 100,
            unit_amount: Number(rental.totalPrice) * 100
          },
          quantity: 1
        }
      ],
      mode: "payment",
      payment_method_types: ["card"],
      success_url: `${config_default.app_url}/payment-success`,
      cancel_url: `${config_default.app_url}/payment-cancel`,
      metadata: {
        rentalId: rental.id,
        userId
      }
    });
    const payment = await tx.payment.create({
      data: {
        rentalId: rental.id,
        amount: rental.totalPrice,
        currency: "usd",
        status: "PENDING",
        paymentMethod: "STRIPE",
        transactionId: session.id
      }
    });
    return {
      payment,
      paymentUrl: session.url
    };
  });
  return result;
};
var confirmPayment = async (sessionId) => {
  const session = await stripe.checkout.sessions.retrieve(sessionId);
  if (session.payment_status !== "paid") {
    throw new Error("Payment is not completed");
  }
  const payment = await prisma.payment.findUniqueOrThrow({
    where: {
      transactionId: sessionId
    }
  });
  if (payment.status === "PAID") {
    throw new Error("Payment already confirmed");
  }
  const result = await prisma.$transaction(async (tx) => {
    const updatedPayment = await tx.payment.update({
      where: {
        id: payment.id
      },
      data: {
        status: "PAID"
      }
    });
    await tx.rental.update({
      where: {
        id: payment.rentalId
      },
      data: {
        status: "CONFIRMED"
      }
    });
    return updatedPayment;
  });
  return result;
};
var getPayment = async (userId) => {
  const payments = await prisma.payment.findMany({
    where: {
      rental: {
        customerId: userId
      }
    },
    include: {
      rental: {
        include: {
          gear: true
        }
      }
    },
    orderBy: {
      createdAt: "desc"
    }
  });
  return payments;
};
var getPaymentById = async (paymentId, userId) => {
  const payment = await prisma.payment.findFirstOrThrow({
    where: {
      id: paymentId,
      rental: {
        customerId: userId
      }
    },
    include: {
      rental: {
        include: {
          gear: true
        }
      }
    }
  });
  return payment;
};
var paymentService = {
  createPayment,
  confirmPayment,
  getPayment,
  getPaymentById
};

